   585→    let targetWindow: any;
   586→
   587→    if (windowTitle) {
   588→      const windows = await getWindows();
   589→      targetWindow = await Promise.all(
   590→        windows.map(async (win: any) => ({
   591→          window: win,
   592→          title: await win.getTitle(),
   593→        }))
   594→      ).then(
   595→        (windowsWithTitles) =>
   596→          windowsWithTitles.find((w) => w.title.includes(windowTitle))?.window
   597→      );
   598→
   599→      if (!targetWindow) {
   600→        throw new Error(
   601→          `Window with title containing "${windowTitle}" not found`
   602→        );
   603→      }
   604→    } else {
   605→      targetWindow = await getActiveWindow();
   606→    }
   607→
   608→    const windowName = await targetWindow.getTitle();
   609→
   610→    switch (action) {
   611→      case "focus":
   612→        await targetWindow.focus();
   613→        return `Focused window: "${windowName}"`;
   614→
   615→      case "move":
   616→        if (x === undefined || y === undefined) {
   617→          throw new Error("Move action requires x and y coordinates");
   618→        }
   619→        await targetWindow.move(new Point(x, y));
   620→        return `Moved window "${windowName}" to (${x}, ${y})`;
   621→
   622→      case "resize":
   623→        if (width === undefined || height === undefined) {
   624→          throw new Error("Resize action requires width and height");
   625→        }
   626→        await targetWindow.resize(new Size(width, height));
   627→        return `Resized window "${windowName}" to ${width}x${height}`;
   628→
   629→      case "minimize":
   630→        await targetWindow.minimize();
   631→        return `Minimized window: "${windowName}"`;
   632→
   633→      case "restore":
   634→        await targetWindow.restore();
   635→        return `Restored window: "${windowName}"`;
   636→
   637→      default:
   638→        throw new Error(`Unknown action: ${action}`);
   639→    }
   640→  },
   641→});
   642→
   643→// ============== ADVANCED AUTOMATION TOOLS ==============
   644→
   645→// Tool 17: Wait and Find on Screen
   646→server.addTool({
   647→  name: "waitForImage",
   648→  description: "Wait for an image to appear on screen and return its location.",
   649→  parameters: z.object({
   650→    imagePath: z.string().describe("Path to the template image file"),
   651→    timeoutMs: z.number().default(5000).describe("Timeout in milliseconds"),
   652→    confidence: z
   653→      .number()
   654→      .min(0)
   655→      .max(1)
   656→      .default(0.8)
   657→      .describe("Match confidence (0-1)"),
   658→  }),
   659→  execute: async ({ imagePath, timeoutMs, confidence }) => {
   660→    return `Image matching functionality requires additional setup. Would wait for image "${imagePath}" with confidence ${confidence} for ${timeoutMs}ms.`;
   661→  },
   662→});
   663→
   664→// Tool 18: Sleep/Delay
   665→server.addTool({
   666→  name: "sleep",
   667→  description: "Pause execution for a specified amount of time.",
   668→  parameters: z.object({
   669→    ms: z.number().describe("Time to sleep in milliseconds"),
   670→  }),
   671→  execute: async ({ ms }) => {
   672→    await new Promise((resolve) => setTimeout(resolve, ms));
   673→    return `Slept for ${ms} milliseconds`;
   674→  },
   675→});
   676→
   677→// Tool 19: Complex Mouse Path Movement
   678→server.addTool({
   679→  name: "mouseMovePath",
   680→  description: "Move mouse along a path of coordinates with smooth animation.",
   681→  parameters: z.object({
   682→    path: z
   683→      .array(z.number())
   684→      .describe(
   685→        "Array of coordinates to move through (alternating x,y values: [x1,y1,x2,y2,...])"
   686→      ),
   687→  }),
   688→  execute: async ({ path }) => {
   689→    requireNutjs();
   690→
   691→    // Validate that we have an even number of coordinates
   692→    if (path.length % 2 !== 0) {
   693→      throw new Error(
   694→        "Path array must contain an even number of values (alternating x,y coordinates)"
   695→      );
   696→    }
   697→
   698→    // Convert flat array to Point objects
   699→    const points: any[] = [];
   700→    for (let i = 0; i < path.length; i += 2) {
   701→      points.push(new Point(path[i], path[i + 1]));
   702→    }
   703→
   704→    await mouse.move(points);
   705→    return `Mouse moved along path with ${points.length} points`;
   706→  },
   707→});
   708→
   709→// Tool 20: System Key Combinations
   710→server.addTool({
   711→  name: "systemCommand",
   712→  description:
   713→    "Execute common system key combinations (copy, paste, undo, etc.).",
   714→  parameters: z.object({
   715→    command: z
   716→      .enum([
   717→        "copy",
   718→        "paste",
   719→        "cut",
   720→        "undo",
   721→        "redo",
   722→        "selectAll",
   723→        "save",
   724→        "quit",
   725→        "minimize",
   726→        "switchApp",
   727→        "newTab",
   728→        "closeTab",
   729→      ])
   730→      .describe("System command to execute"),
   731→  }),
   732→  execute: async ({ command }) => {
   733→    if (nutjsAvailable) {
   734→      const isMac = process.platform === "darwin";
   735→      const cmdKey = isMac ? Key.LeftSuper : Key.LeftControl;
