   820→      }
   821→    } else {
   822→      // Fallback using AppleScript for macOS
   823→      const commandMap: { [key: string]: string } = {
   824→        copy: 'keystroke "c" using command down',
   825→        paste: 'keystroke "v" using command down',
   826→        cut: 'keystroke "x" using command down',
   827→        undo: 'keystroke "z" using command down',
   828→        redo: 'keystroke "z" using {command down, shift down}',
   829→        selectAll: 'keystroke "a" using command down',
   830→        save: 'keystroke "s" using command down',
   831→        quit: 'keystroke "q" using command down',
   832→        minimize: 'keystroke "m" using command down',
   833→        switchApp: "keystroke tab using command down",
   834→        newTab: 'keystroke "t" using command down',
   835→        closeTab: 'keystroke "w" using command down',
   836→      };
   837→
   838→      const script = commandMap[command];
   839→      if (script) {
   840→        child_process.execSync(
   841→          `osascript -e 'tell application "System Events" to ${script}'`
   842→        );
   843→        return `Executed ${command} command using AppleScript`;
   844→      } else {
   845→        throw new Error(`Unknown command: ${command}`);
   846→      }
   847→    }
   848→  },
   849→});
